var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"헉......! 헉......!","JPN":"はあ……！　はあ……！","ENG":"*Huff* *Huff*","TWN":"呼……！呼……！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"잠깐! 잠깐만 기다려!","JPN":"ちょっと！　ま、待って！","ENG":"Wait! Hold on for a second!","TWN":"等等！等一下！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"네? 기세등등하게 찾으러 가자고 하더니 설마 벌써 지쳤어요?","JPN":"はい？　やる気満々で探しに行くと言っていたのに、もう疲れたのですか？","ENG":"What? You were excited to go after him. You can't be tired already.","TWN":"剛才說去找他的時候還氣勢洶洶的，這麼快就已經累了嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그래, 지쳤다.","JPN":"そう……もう疲れたの。","ENG":"Yes, I am.","TWN":"是啊，我累了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"같은 카운터라고 해도 난 신체능력이 그다지 좋진 않단 말야.","JPN":"同じカウンターでも、アタシは身体能力がそこまで高くないから。","ENG":"I may be a Counter, but I'm not as athletic as you.","TWN":"雖然都是制裁者，但我的身體素質並不好。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"작전 때는 힘들지 않게 잘 에스코트하더니 오늘은 왜 눈 맞은 토끼처럼 뛰어다니는 거야?","JPN":"作戦の時は疲れないように、ちゃんとエスコートしてくれてたのに、今日はなんでウサギみたいに飛び回ってるわけ？","ENG":"You kept pace with me when we operated together before. And now you're running around like a chicken with its head cut off!","TWN":"之前作戰的時候沒見妳讓我這麼累，今天怎麼跟打了雞血似的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"아하하. 그때는 의뢰인이셨잖아요?","JPN":"アハハ、あの時は依頼人だったじゃないですか。","ENG":"Ah hah hah! You were my client back then.","TWN":"啊哈哈，因為那時候妳是委託人啊？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"지금이라도 알트 소대를 고용하시면 편안하게 모셔다 드리겠습니다.","JPN":"今でもアルト小隊を雇用するのであれば、楽にエスコートして差し上げますよ。","ENG":"Hire the ALT Squad again, and I'll serve you to the best of my ability.","TWN":"如果現在妳雇傭阿爾特小隊的話，我照樣會讓妳舒舒服服的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"물론 현장 할증은 붙지만요.","JPN":"もちろん、現場割増がつきますが。","ENG":"For an on-site service premium, of course.","TWN":"當然這是需要加錢的。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"부사장 아줌마랑 판박이네, 아주.","JPN":"副社長のおばさんとそっくりね。","ENG":"You're just like the vice president lady.","TWN":"妳怎麼跟那個副總大嬸一模一樣。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"아무튼, 지금 어디로 가고 있는 거야? 그 녀석이 어디 숨어 있는지 단서라도 있어?","JPN":"とにかく、今どこに向かってるの？　あいつがどこに隠れているのか、手がかりでもあるの？","ENG":"Anyway, where are we going? Do you have an idea where he might be?","TWN":"不過，我們現在是要去哪裡？妳知道那個傢伙躲在哪裡嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"아뇨. 그런 건 없어요.","JPN":"いえ、そのようなものはありません。","ENG":"No, I don't.","TWN":"不，我不知道。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"뭐어? 그럼 어떻게 찾겠다는 건데?","JPN":"えっ？　じゃあ、どうやって見つける気？","ENG":"What? Then, how are we going to find him?","TWN":"什麼？那妳要怎麼找到他？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"괜찮아요. 애초에 저희 쪽에서 찾을 필요가 없거든요.","JPN":"大丈夫です。元々こっちが探す必要はないので。","ENG":"Don't worry. We don't have to.","TWN":"不用擔心，其實根本不用我們去找他。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"아마 범인은 우리가 이렇게 그룹을 나눌 것도 예상하고 희생자들을 움직였을 거예요.","JPN":"犯人は私たちがグループに別れたことをすでに予想して、犠牲者たちを動かしているはずです。","ENG":"I bet the perpetrator knew we'd split and mobilized the victims.","TWN":"兇手如此操控受害者，應該早就預想到我們會分成小隊。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그러니 이제는 선배가 습격하기 적당한 곳을 찾아서 기다리면 되죠.","JPN":"だから私たちは先輩が襲って来ると思われる場所を探して、待ち伏せすればいいのです。","ENG":"All we have to do is find a perfect spot for Shiyoon to ambush us and wait there.","TWN":"所以我們只要在前輩認為適合襲擊的地方等他就可以了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"......그런 애매한 방법이 정말 통한다고?","JPN":"……そんな適当な方法が通じるわけ？","ENG":"Are you sure such a haphazard plan will work?","TWN":"……這個方法真的行得通嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"이거 참, 역시 서윤 양과는 마음이 잘 통한다니까요.","JPN":"まったく、さすがアオイさんとは気が合うようですね。","ENG":"Gosh, Seo Yoon. It's as if you and I are spiritually connected.","TWN":"果然我和徐芸小姐心意相通呢。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"말로 하지 않아도 제 생각을 정확히 읽고 계시잖아요?","JPN":"言葉にしなくても、僕の考えをちゃんと読めているじゃないですか？","ENG":"You read me like an open book.","TWN":"不用我說，妳都知道我在想什麼。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"보다시피 통한 것 같네요.","JPN":"見てのとおり、通じたようですね。","ENG":"Apparently, it worked.","TWN":"怎麼樣，這個辦法是不是很管用。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"좋아. 그럼 어떻게 싸울 거야? 작전이라도 있어?","JPN":"じゃあ、これからどう戦う気？　作戦でもあるの？","ENG":"Alright, then how are we going to fight him? Have you thought of that, too?","TWN":"好，那之後呢？有什麼作戰計畫嗎？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"없는 건 아니지만, 그 전에 선배에게 물어볼 게 있어요.","JPN":"ないわけではありませんが、その前に先輩に聞きたいことがあるんです。","ENG":"I have, but let me ask him something first.","TWN":"也不是沒有，但那之前我有問題想問前輩。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"물어본다고? 뭘?","JPN":"聞きたい事って何？","ENG":"Ask him what?","TWN":"什麼問題？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"하하. 죄송하지만 밤이 얼마 남지 않아서요, 서윤 양.","JPN":"ハハ、申し訳ありませんが、夜ももうすぐ明けてしまいます。","ENG":"Hah hah. I'm sorry, Seo Yoon, but the night is almost over.","TWN":"哈哈，徐芸小姐，很抱歉夜晚已所剩不多。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"저도 나름대로 바쁜 몸이라 대화를 나누기엔 시간이 없네요.","JPN":"僕も忙しいので、お相手できる時間がありません。","ENG":"I'd love to talk, but I don't have the time.","TWN":"我很忙，沒時間回答妳的問題。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"그러니 질문이 있다면 절 쓰러뜨리고 하시는 편이 어떨까요?","JPN":"だから、質問があるのであれば倒してからというのはいかがでしょう？","ENG":"So, why don't we fight first and ask questions later?","TWN":"所以妳的問題，等打敗我之後再問吧。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"좋아. 선배가 그렇게 말한다면.","JPN":"わかった。先輩がそう言うなら。","ENG":"Alright, if you say so.","TWN":"好，那我就恭敬不如從命了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"......그리고 실비아 씨.","JPN":"……それからシルビアさん。","ENG":"And Sylvia.","TWN":"……希爾維亞。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Yes?","TWN":"嗯？"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"전투가 벌어지는 대로 이 일대에 최대한 강한 전자기 펄스를 펼쳐 주세요.","JPN":"戦闘が始まったら、この一帯に一番強い電磁パルスを張ってください。","ENG":"As soon as the fight begins, cover this area with as powerful an EMP as you can muster.","TWN":"戰鬥一開始，就麻煩妳在這一帶儘量展開強烈的電磁脈衝。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"전자기 펄스? 그건 사람에겐 별 효과가 없는데?","JPN":"電磁パルス？　人には何の効果もないわよ？","ENG":"EMP? Why? It doesn't work against people.","TWN":"電磁脈衝？可那個對人沒什麼效果。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"제게 생각이 있어요. 부탁드릴게요.","JPN":"私に考えがあるのです。お願いします。","ENG":"I've got an idea. Please do it.","TWN":"我有辦法，就拜託妳了。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"SEOYOON_ALT_XMAS_NULL","text":{"KOREA":"그럼 알트 소대 서윤, 갑니다!","JPN":"では、アルト小隊アオイ・シズカ、参ります！","ENG":"Alright, then here comes Seo Yoon, of the ALT Squad!","TWN":"阿爾特小隊的徐芸，進攻！"},"stage":{"bg":"X_MAS_HOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_XMAS_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};